CREATE TABLE steam_tag(
   appid                             INTEGER  NOT NULL PRIMARY KEY 
  ,2d                                INTEGER  NOT NULL
  ,action                            INTEGER  NOT NULL
  ,anime                             INTEGER  NOT NULL
  ,arcade                            INTEGER  NOT NULL
  ,battle_royale                     INTEGER  NOT NULL
  ,detective                         INTEGER  NOT NULL
  ,fps                               INTEGER  NOT NULL
  ,horror                            INTEGER  NOT NULL
  ,indie                             INTEGER  NOT NULL
  ,open_world                        INTEGER  NOT NULL
  ,simulation                        INTEGER  NOT NULL
);
